// Hand-written extras: stretching library + a handful of compound
// exercises that the Strong Curves seed didn't include but the new
// routines (Starting Strength, 5/3/1) reference.
//
// Format matches the existing autogenerated `STRONG_CURVES_EXERCISES`
// shape (`Omit<Exercise, 'isCustom' | 'profileId'>`) so the seed
// loader can merge both lists with the same enrichment pass.

import type { EquipmentTag, Exercise, MuscleGroup } from '../types';

type ExerciseSeed = Omit<Exercise, 'isCustom' | 'profileId'>;

// --- Stretching ------------------------------------------------------------

function stretch(opts: {
  id: string;
  name: string;
  primary: MuscleGroup[];
  secondary?: MuscleGroup[];
  perSide?: boolean;
  equipment?: EquipmentTag[];
  diagram?: string;
  instructions: string[];
}): ExerciseSeed {
  return {
    id: opts.id,
    name: opts.name,
    category: 'stretching',
    primaryMuscles: opts.primary,
    secondaryMuscles: opts.secondary ?? [],
    measurementType: 'time_seconds',
    defaultRestSeconds: 15,
    perSide: opts.perSide ?? false,
    usesBarbell: false,
    requiredEquipment: opts.equipment ?? ['yoga-mat'],
    instructions: opts.instructions,
    ...(opts.diagram ? { diagram: opts.diagram } : {}),
  };
}

