// --- Compound exercises the Strong Curves seed lacks -----------------------

function compound(opts: {
  id: string;
  name: string;
  category: Exercise['category'];
  primary: MuscleGroup[];
  secondary?: MuscleGroup[];
  measurementType?: Exercise['measurementType'];
  defaultRestSeconds?: number;
  usesBarbell?: boolean;
  perSide?: boolean;
  equipment: EquipmentTag[];
  diagram?: string;
  instructions: string[];
}): ExerciseSeed {
  return {
    id: opts.id,
    name: opts.name,
    category: opts.category,
    primaryMuscles: opts.primary,
    secondaryMuscles: opts.secondary ?? [],
    measurementType: opts.measurementType ?? 'weight_reps',
    defaultRestSeconds: opts.defaultRestSeconds ?? 120,
    perSide: opts.perSide ?? false,
    usesBarbell: opts.usesBarbell ?? false,
    requiredEquipment: opts.equipment,
    instructions: opts.instructions,
    ...(opts.diagram ? { diagram: opts.diagram } : {}),
  };
}

